#!/usr/bin/env node
/**
 * Push the Four Lanes Today snapshot card into Notion.
 *
 * Reads `wiki/cockpit/four-lanes-today.md` (generated by
 * `scripts/four-lanes-snapshot.mjs`) and replaces the body of a target
 * Notion page with Notion-block equivalents of the markdown.
 *
 * Target page id resolution order:
 *   1. NOTION_PAGE_FOUR_LANES_CARD env var
 *   2. config/notion-database-ids.json -> fourLanesCard
 *
 * If neither is set, the script prints setup instructions and exits 0
 * (so a wired-up cron job stays green until Ben configures it).
 *
 * Usage:
 *   node scripts/sync-four-lanes-card-to-notion.mjs              # push
 *   node scripts/sync-four-lanes-card-to-notion.mjs --dry-run    # preview blocks
 *   node scripts/sync-four-lanes-card-to-notion.mjs --rebuild    # also refresh the markdown first
 */
import { Client } from '@notionhq/client'
import { execSync } from 'node:child_process'
import { readFileSync, existsSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { dirname, join } from 'node:path'
import { markdownToBlocks, clearPage, appendBlocks } from './lib/notion-md-blocks.mjs'

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)

await import(join(__dirname, 'lib/load-env.mjs'))

const args = process.argv.slice(2)
const DRY_RUN = args.includes('--dry-run')
const REBUILD_FIRST = args.includes('--rebuild')

const REPO_ROOT = join(__dirname, '..')
const COCKPIT_PATH = join(REPO_ROOT, 'wiki/cockpit/four-lanes-today.md')
const CONFIG_PATH = join(REPO_ROOT, 'config/notion-database-ids.json')

const sleep = (ms) => new Promise((r) => setTimeout(r, ms))
const log = (m) => console.log(`[four-lanes-card] ${m}`)

function resolvePageId() {
  if (process.env.NOTION_PAGE_FOUR_LANES_CARD) return process.env.NOTION_PAGE_FOUR_LANES_CARD
  if (existsSync(CONFIG_PATH)) {
    const cfg = JSON.parse(readFileSync(CONFIG_PATH, 'utf-8'))
    if (cfg.fourLanesCard) return cfg.fourLanesCard
  }
  return null
}

async function main() {
  const pageId = resolvePageId()
  if (!pageId) {
    log('SKIP: target page id not set.')
    log('To enable: create a Notion page (e.g. "Four Lanes Today"), copy its id (32 hex chars or formatted),')
    log('and either:')
    log('  (a) add  "fourLanesCard": "<page-id>"  to config/notion-database-ids.json, or')
    log('  (b) export NOTION_PAGE_FOUR_LANES_CARD=<page-id> in .env.local.')
    log('Skipping push. Cron job stays green.')
    return
  }
  if (!process.env.NOTION_TOKEN) {
    log('SKIP: NOTION_TOKEN env var not set. Cron job stays green.')
    return
  }

  if (REBUILD_FIRST) {
    log('refreshing markdown via four-lanes-snapshot.mjs')
    execSync(`node ${join(__dirname, 'four-lanes-snapshot.mjs')}`, { stdio: 'inherit' })
  }

  if (!existsSync(COCKPIT_PATH)) {
    log(`ERROR: ${COCKPIT_PATH} not found. Run with --rebuild or run scripts/four-lanes-snapshot.mjs first.`)
    process.exit(1)
  }

  const md = readFileSync(COCKPIT_PATH, 'utf-8')
  const blocks = markdownToBlocks(md)
  log(`parsed ${blocks.length} blocks from ${COCKPIT_PATH}`)

  if (DRY_RUN) {
    log('DRY-RUN: would replace page body with the following block types:')
    const types = blocks.reduce((acc, b) => ((acc[b.type] = (acc[b.type] || 0) + 1), acc), {})
    for (const [t, n] of Object.entries(types)) log(`  ${t}: ${n}`)
    log(`target page id: ${pageId}`)
    return
  }

  const notion = new Client({ auth: process.env.NOTION_TOKEN })
  log(`clearing existing body of ${pageId}`)
  await clearPage(notion, pageId)
  log(`appending ${blocks.length} blocks`)
  await appendBlocks(notion, pageId, blocks)
  log('done')
}

main().catch((err) => {
  console.error('[four-lanes-card] fatal:', err.message)
  process.exit(1)
})
